Trigger.script:
aard.itemIgnore = { ["Name"]="have a seperate trigger for names", ["Keywords"]="keywords are often not unique enough, item ids work better, dont store this data", ["Score"]="This score is assigned by compare set and is variable depending on class, dont store this data", ["Owned By"]="This score is assigned by compare set and is variable depending on class, dont store this data", ["Holding"]="temporary value, dont store this data", ["Items Inside"]="temporary value, dont store this data", ["Tot Weight"]="temporary value, dont store this data", ["Item Burden"]="temporary value, dont store this data", ["Uses Left"]="temporary value, dont store this data", ["Duration"]="most useful lights should be permanent?? dont think this should be stored", ["Market Item Number"]="temporary value, dont store this data", ["Item is being sold by"]="temporary value, dont store this data", ["Auction will end in"]="temporary value, dont store this data", }
if not aard.itemIgnore[matches[2]] then local a1 = matches[2] local v1 = matches[3] echo("\n"..a1..":"..v1)
if matches[5] then local a2 = matches[5] local v2 = matches[6] echo("\n"..a2..":"..v2) end end

--Did not combine this in the stats trigger because the Heal rate for mana is labeled "Magic"
--the string "Magic" is also used for resists.
local v1 = matches[2]
local v2 = matches[3]
echo("\nhealhp:"..v1)
echo("\nhealmn:"..v2)
